1599		void help() override
1600		{
1601			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
1602			log("\n");
1603			log("    write_smt2 [options] [filename]\n");
1604			log("\n");
1605			log("Write a SMT-LIBv2 [1] description of the current design. For a module with name\n");
1606			log("'<mod>' this will declare the sort '<mod>_s' (state of the module) and will\n");
1607			log("define and declare functions operating on that state.\n");
1608			log("\n");
1609			log("The following SMT2 functions are generated for a module with name '<mod>'.\n");
1610			log("Some declarations/definitions are printed with a special comment. A prover\n");
1611			log("using the SMT2 files can use those comments to collect all relevant metadata\n");
1612			log("about the design.\n");
1613			log("\n");
1614			log("    ; yosys-smt2-module <mod>\n");
1615			log("    (declare-sort |<mod>_s| 0)\n");
1616			log("        The sort representing a state of module <mod>.\n");
1617			log("\n");
1618			log("    (define-fun |<mod>_h| ((state |<mod>_s|)) Bool (...))\n");
1619			log("        This function must be asserted for each state to establish the\n");
1620			log("        design hierarchy.\n");
1621			log("\n");
1622			log("    ; yosys-smt2-input <wirename> <width>\n");
1623			log("    ; yosys-smt2-output <wirename> <width>\n");
1624			log("    ; yosys-smt2-register <wirename> <width>\n");
1625			log("    ; yosys-smt2-wire <wirename> <width>\n");
1626			log("    (define-fun |<mod>_n <wirename>| (|<mod>_s|) (_ BitVec <width>))\n");
1627			log("    (define-fun |<mod>_n <wirename>| (|<mod>_s|) Bool)\n");
1628			log("        For each port, register, and wire with the 'keep' attribute set an\n");
1629			log("        accessor function is generated. Single-bit wires are returned as Bool,\n");
1630			log("        multi-bit wires as BitVec.\n");
1631			log("\n");
1632			log("    ; yosys-smt2-cell <submod> <instancename>\n");
1633			log("    (declare-fun |<mod>_h <instancename>| (|<mod>_s|) |<submod>_s|)\n");
1634			log("        There is a function like that for each hierarchical instance. It\n");
1635			log("        returns the sort that represents the state of the sub-module that\n");
1636			log("        implements the instance.\n");
1637			log("\n");
1638			log("    (declare-fun |<mod>_is| (|<mod>_s|) Bool)\n");
1639			log("        This function must be asserted 'true' for initial states, and 'false'\n");
1640			log("        otherwise.\n");
1641			log("\n");
1642			log("    (define-fun |<mod>_i| ((state |<mod>_s|)) Bool (...))\n");
1643			log("        This function must be asserted 'true' for initial states. For\n");
1644			log("        non-initial states it must be left unconstrained.\n");
1645			log("\n");
1646			log("    (define-fun |<mod>_t| ((state |<mod>_s|) (next_state |<mod>_s|)) Bool (...))\n");
1647			log("        This function evaluates to 'true' if the states 'state' and\n");
1648			log("        'next_state' form a valid state transition.\n");
1649			log("\n");
1650			log("    (define-fun |<mod>_a| ((state |<mod>_s|)) Bool (...))\n");
1651			log("        This function evaluates to 'true' if all assertions hold in the state.\n");
1652			log("\n");
1653			log("    (define-fun |<mod>_u| ((state |<mod>_s|)) Bool (...))\n");
1654			log("        This function evaluates to 'true' if all assumptions hold in the state.\n");
1655			log("\n");
1656			log("    ; yosys-smt2-assert <id> <filename:linenum>\n");
1657			log("    (define-fun |<mod>_a <id>| ((state |<mod>_s|)) Bool (...))\n");
1658			log("        Each $assert cell is converted into one of this functions. The function\n");
1659			log("        evaluates to 'true' if the assert statement holds in the state.\n");
1660			log("\n");
1661			log("    ; yosys-smt2-assume <id> <filename:linenum>\n");
1662			log("    (define-fun |<mod>_u <id>| ((state |<mod>_s|)) Bool (...))\n");
1663			log("        Each $assume cell is converted into one of this functions. The function\n");
1664			log("        evaluates to 'true' if the assume statement holds in the state.\n");
1665			log("\n");
1666			log("    ; yosys-smt2-cover <id> <filename:linenum>\n");
1667			log("    (define-fun |<mod>_c <id>| ((state |<mod>_s|)) Bool (...))\n");
1668			log("        Each $cover cell is converted into one of this functions. The function\n");
1669			log("        evaluates to 'true' if the cover statement is activated in the state.\n");
1670			log("\n");
