1709			log("\n");
1710			log("[1] For more information on SMT-LIBv2 visit http://smt-lib.org/ or read David\n");
1711			log("R. Cok's tutorial: https://smtlib.github.io/jSMTLIB/SMTLIBTutorial.pdf\n");
