1726			log("\n");
1727			log("        ; we need QF_UFBV for this proof\n");
1728			log("        (set-logic QF_UFBV)\n");
1729			log("\n");
1730			log("        ; insert the auto-generated code here\n");
1731			log("        %%%%\n");
1732			log("\n");
