516		void export_reduce(RTLIL::Cell *cell, std::string expr, bool identity_val)
517		{
518			RTLIL::SigSpec sig_y = sigmap(cell->getPort(ID::Y));
519			std::string processed_expr;
520	
521			for (char ch : expr)
522				if (ch == 'A' || ch == 'B') {
523					RTLIL::SigSpec sig = sigmap(cell->getPort(stringf("\\%c", ch)));
524					for (auto bit : sig)
525						processed_expr += " " + get_bool(bit);
526					if (GetSize(sig) == 1)
527						processed_expr += identity_val ? " true" : " false";
528				} else
529					processed_expr += ch;
530	
531			if (verbose)
532				log("%*s-> import cell: %s\n", 2+2*GetSize(recursive_cells), "", cell);
533	
534			decls.push_back(stringf("(define-fun |%s#%d| ((state |%s_s|)) Bool %s) ; %s\n",
535					get_id(module), idcounter, get_id(module), processed_expr.c_str(), log_signal(sig_y)));
536			register_boolvec(sig_y, idcounter++);
537			recursive_cells.erase(cell);
538		}
