			recursive_cells.erase(cell);
			return;
		}

		if (cell->type == ID($and)) return export_bvop(cell, "(bvand A B)");
		if (cell->type == ID($or)) return export_bvop(cell, "(bvor A B)");
		if (cell->type == ID($xor)) return export_bvop(cell, "(bvxor A B)");

