void add_nid_sig(int nid, const SigSpec &sig)
{
	if (verbose)
		f << indent << stringf("; %d %s\n", nid, log_signal(sig));

	for (int i = 0; i < GetSize(sig); i++)
		bit_nid[sig[i]] = make_pair(nid, i);

	sig_nid[sig] = nid;
	nid_width[nid] = GetSize(sig);
}

