		if (cell->type == ID($_DFF_N_))
			negedge = true;

		if (cell->type == ID($dff) && !cell->getParam(ID::CLK_POLARITY).as_bool())
			negedge = true;

		if (!info_filename.empty())
			info_clocks[nid] |= negedge ? 2 : 1;

		if (ywmap_json.active())
			ywmap_clock_bits[sig_c] |= negedge ? 2 : 1;
